"""Реализация tools для агента."""

from __future__ import annotations

import json
import sys
from typing import Any

from metadata import get_sql_examples, get_table_metadata

from .db import OracleClient, UnsafeSQLError

KNOWN_TABLES = {"client_product"}


def _trim(s: str, n: int = 4000) -> str:
    return s if len(s) <= n else s[:n] + " …[truncated]"


# === Tool: inspect_schema ===

def tool_inspect_schema(table: str) -> str:
    """Возвращает компактное описание таблицы и её полей."""
    if table.lower() not in KNOWN_TABLES:
        return json.dumps(
            {
                "error": f"Таблица '{table}' не найдена. "
                f"Доступные: {sorted(KNOWN_TABLES)}",
            },
            ensure_ascii=False,
        )

    meta = get_table_metadata(table)
    fields_compact: list[dict[str, Any]] = []
    for fname, fmeta in meta["fields"].items():
        fields_compact.append(
            {
                "name": fname,
                "type": fmeta.get("type"),
                "category": fmeta.get("category"),
                "description": fmeta.get("description"),
                "aggregation_between_clients": fmeta.get(
                    "aggregation_between_clients"
                ),
                "aggregation_between_month": fmeta.get(
                    "aggregation_between_month"
                ),
            }
        )

    examples = get_sql_examples(table)
    payload = {
        "table": meta["table_name"],
        "description": meta["description"].strip(),
        "fields": fields_compact,
        "sql_examples": examples,
        "rules": [
            "Oracle dialect (FETCH FIRST N ROWS ONLY вместо LIMIT).",
            "Даты — DATE 'YYYY-MM-DD' литералы.",
            "MONTH_DT = последний день месяца. Для последнего доступного месяца — подзапрос (SELECT MAX(MONTH_DT) FROM client_product).",
            "Не суммируй ИТОГОВОЕ ПОЛЕ с его составляющими (см. описания).",
            "Для имён компаний используй UPPER(...) LIKE '%' || UPPER('...') || '%'.",
        ],
    }
    return json.dumps(payload, ensure_ascii=False, default=str)


# === Tool: execute_sql ===

def tool_execute_sql(sql: str, oracle: OracleClient) -> str:
    """Запускает SQL и возвращает результат в JSON."""
    try:
        result = oracle.execute(sql)
    except UnsafeSQLError as e:
        return json.dumps(
            {"ok": False, "error": f"UnsafeSQLError: {e}"},
            ensure_ascii=False,
        )
    except Exception as e:  # oracledb.DatabaseError и пр.
        msg = str(e).splitlines()[0]
        return json.dumps(
            {
                "ok": False,
                "error": f"{type(e).__name__}: {msg}",
                "hint": "Проверь имена полей по inspect_schema и Oracle-синтаксис.",
            },
            ensure_ascii=False,
        )

    preview_rows = result.rows[:50]
    payload = {
        "ok": True,
        "columns": result.columns,
        "row_count": result.row_count,
        "truncated": result.truncated,
        "rows": preview_rows,
    }
    print(
        f"[execute_sql] rows={result.row_count} columns={result.columns}",
        file=sys.stderr,
    )
    return _trim(json.dumps(payload, ensure_ascii=False, default=str), 8000)


# === Tool: validate_result ===

def tool_validate_result(
    columns: list[str] | None,
    row_count: int,
    rows_preview: list[list[Any]] | None,
    expectations: dict[str, Any] | None,
) -> str:
    """Sanity-check над результатом."""
    expectations = expectations or {}
    rows_preview = rows_preview or []
    columns = columns or []

    issues: list[str] = []
    notes: list[str] = []

    min_rows = int(expectations.get("min_rows", 0))
    max_rows = expectations.get("max_rows")
    if row_count < min_rows:
        issues.append(
            f"row_count={row_count} меньше ожидаемого минимума {min_rows}"
        )
    if isinstance(max_rows, int) and row_count > max_rows:
        issues.append(
            f"row_count={row_count} превышает ожидаемый максимум {max_rows}"
        )

    non_null_cols = expectations.get("non_null_columns") or []
    for col in non_null_cols:
        if col not in columns:
            issues.append(
                f"Ожидалась колонка '{col}', но её нет в результате "
                f"({columns})"
            )
            continue
        idx = columns.index(col)
        nulls = sum(1 for r in rows_preview if r[idx] is None)
        if nulls:
            issues.append(
                f"Колонка '{col}' содержит {nulls} NULL "
                f"в первых {len(rows_preview)} строках"
            )

    numeric_ranges = expectations.get("numeric_ranges") or {}
    for col, bounds in numeric_ranges.items():
        if col not in columns:
            issues.append(f"Колонка '{col}' для проверки диапазона не найдена")
            continue
        idx = columns.index(col)
        lo = bounds.get("min")
        hi = bounds.get("max")
        for i, r in enumerate(rows_preview):
            v = r[idx]
            if v is None:
                continue
            try:
                vf = float(v)
            except (TypeError, ValueError):
                issues.append(
                    f"Строка {i}: '{col}'='{v}' не приводится к числу"
                )
                continue
            if lo is not None and vf < lo:
                issues.append(
                    f"Строка {i}: {col}={vf} меньше нижней границы {lo}"
                )
            if hi is not None and vf > hi:
                issues.append(
                    f"Строка {i}: {col}={vf} больше верхней границы {hi}"
                )

    if row_count == 0:
        notes.append(
            "Пустой результат. Возможные причины: слишком узкий фильтр, "
            "не тот месяц, не та компания (LIKE-маска). Проверь и повтори."
        )

    payload = {
        "ok": not issues,
        "issues": issues,
        "notes": notes,
        "summary": (
            "Все проверки пройдены."
            if not issues
            else f"Найдено {len(issues)} проблем(ы); требуется коррекция."
        ),
    }
    return json.dumps(payload, ensure_ascii=False, default=str)


# === Tool: final_answer ===

def tool_final_answer(text: str, supporting_data: Any | None = None) -> dict[str, Any]:
    """Финализирует ответ агента. Сам по себе текст возвращается main loop."""
    return {
        "text": text.strip(),
        "supporting_data": supporting_data,
    }


# === Tool schemas (OpenAI format) ===

