            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "table": {
                        "type": "string",
                        "description": "Имя таблицы. Сейчас доступна только 'client_product'.",
                    }
                },
                "required": ["table"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "execute_sql",
            "description": (
                "Выполняет Oracle SQL (только SELECT/WITH) и возвращает "
                "колонки + строки результата. Используй после inspect_schema."
            ),
            "parameters": {
