            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "validate_result",
            "description": (
                "Sanity-check результата execute_sql. Передай columns, "
                "row_count, rows_preview и expectations (min_rows, "
                "non_null_columns, numeric_ranges)."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "columns": {"type": "array", "items": {"type": "string"}},
                    "row_count": {"type": "integer"},
                    "rows_preview": {
                        "type": "array",
                        "items": {"type": "array"},
                        "description": "Первые ~20 строк результата (как массив массивов).",
                    },
                    "expectations": {
