                            "Опциональные ожидания: min_rows (int), "
                            "max_rows (int), non_null_columns (list[str]), "
                            "numeric_ranges ({col: {min, max}})."
                        ),
                    },
                },
                "required": ["columns", "row_count"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "final_answer",
            "description": (
                "Финальный естественно-языковой ответ пользователю с цифрами и "
                "интерпретацией. Вызывается ОДИН РАЗ в конце пайплайна."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "text": {
                        "type": "string",
                        "description": "Связный ответ на русском с конкретными числами.",
                    },
                    "supporting_data": {
                        "description": "Опциональные сырые цифры/таблица из execute_sql.",
                    },
                },
                "required": ["text"],
            },
        },
    },
]


def dispatch_tool(
    name: str,
    arguments: dict[str, Any],
    oracle: OracleClient,
) -> tuple[str, dict[str, Any] | None]:
    """Возвращает (tool_result_string_for_LLM, final_answer_payload_or_None)."""
    if name == "inspect_schema":
        return tool_inspect_schema(arguments.get("table", "client_product")), None
    if name == "execute_sql":
        sql = arguments.get("sql") or ""
        return tool_execute_sql(sql, oracle), None
    if name == "validate_result":
        return (
            tool_validate_result(
                columns=arguments.get("columns"),
                row_count=int(arguments.get("row_count", 0)),
                rows_preview=arguments.get("rows_preview"),
                expectations=arguments.get("expectations"),
            ),
            None,
        )
    if name == "final_answer":
        payload = tool_final_answer(
            text=arguments.get("text", ""),
            supporting_data=arguments.get("supporting_data"),
        )
        return json.dumps({"ok": True}, ensure_ascii=False), payload
    return (
        json.dumps(
            {"ok": False, "error": f"Unknown tool: {name}"},
            ensure_ascii=False,
        ),
        None,
    )

"""Oracle-коннектор и безопасное выполнение SELECT-запросов."""

from __future__ import annotations

import re
from dataclasses import dataclass
from typing import Any

import oracledb

from .config import Config

MAX_ROWS = 1000
QUERY_TIMEOUT_SEC = 60

_FORBIDDEN = re.compile(
    r"\b(INSERT|UPDATE|DELETE|MERGE|DROP|TRUNCATE|ALTER|CREATE|GRANT|REVOKE|"
    r"COMMIT|ROLLBACK|EXECUTE|BEGIN|CALL)\b",
    re.IGNORECASE,
)


class UnsafeSQLError(ValueError):
    """SQL содержит запрещённые DDL/DML операции."""


@dataclass
class QueryResult:
    columns: list[str]
    rows: list[list[Any]]
    row_count: int
    truncated: bool

    def to_dict(self) -> dict[str, Any]:
        return {
            "columns": self.columns,
            "rows": self.rows,
            "row_count": self.row_count,
            "truncated": self.truncated,
        }


def assert_select_only(sql: str) -> str:
    """Простая защита: разрешён только один SELECT/WITH-statement, никаких ; и DDL/DML."""
    stripped = sql.strip().rstrip(";").strip()
    if not stripped:
        raise UnsafeSQLError("Пустой SQL")

    head = stripped.lstrip("(").lstrip().split(None, 1)[0].upper()
    if head not in {"SELECT", "WITH"}:
        raise UnsafeSQLError(
            f"Разрешены только SELECT/WITH. Получено: '{head}'."
        )

    if ";" in stripped:
        raise UnsafeSQLError("Несколько statement'ов (;) запрещены.")

    if _FORBIDDEN.search(stripped):
        raise UnsafeSQLError("SQL содержит запрещённые DDL/DML конструкции.")

    return stripped


class OracleClient:
    """Тонкая обёртка вокруг oracledb с read-only исполнением."""

    def __init__(self, config: Config):
        self._config = config

    def connect(self) -> oracledb.Connection:
        return oracledb.connect(
            user=self._config.oracle_username,
            password=self._config.oracle_password,
            dsn=self._config.oracle_dsn,
        )

    def execute(self, sql: str, max_rows: int = MAX_ROWS) -> QueryResult:
        safe_sql = assert_select_only(sql)
        with self.connect() as conn:
            conn.call_timeout = QUERY_TIMEOUT_SEC * 1000
            with conn.cursor() as cur:
                cur.execute(safe_sql)
                columns = [str(d[0]) for d in (cur.description or [])]
                fetched = cur.fetchmany(max_rows + 1)
                truncated = len(fetched) > max_rows
                rows_raw = fetched[:max_rows]
                rows = [[_normalize(v) for v in row] for row in rows_raw]
                return QueryResult(
                    columns=columns,
                    rows=rows,
                    row_count=len(rows),
                    truncated=truncated,
                )


def _normalize(value: Any) -> Any:
    """Приводит Oracle-значения к JSON-сериализуемому виду."""
    import datetime
    import decimal

    if value is None:
        return None
    if isinstance(value, (datetime.datetime, datetime.date)):
        return value.isoformat()
    if isinstance(value, decimal.Decimal):
        if value == value.to_integral_value():
            return int(value)
        return float(value)
    if isinstance(value, (bytes, bytearray)):
        return value.decode("utf-8", errors="replace")
    return value

"""OpenAI-совместимый клиент (Ollama)."""

from __future__ import annotations

from openai import OpenAI

from .config import Config


def make_client(config: Config) -> OpenAI:
    """Создаёт OpenAI-клиент, нацеленный на Ollama base_url."""
    return OpenAI(
        base_url=config.api_url,
        api_key=config.api_key,
    )

"""Тест agent loop с моками OpenAI и Oracle.

Проверяем, что:
- модель делает tool_call inspect_schema → execute_sql → validate_result → final_answer,
- main loop правильно подаёт tool_results обратно,
- финальный ответ соответствует payload tool_call'а final_answer.
"""

import json
from dataclasses import dataclass
from typing import Any

from text2sql.agent import run_agent
from text2sql.config import Config
from text2sql.db import QueryResult


@dataclass
class _ToolCallStub:
    id: str
    function: Any


@dataclass
class _FuncStub:
    name: str
    arguments: str


@dataclass
class _MessageStub:
    content: str | None
    tool_calls: list[_ToolCallStub] | None


@dataclass
class _ChoiceStub:
    message: _MessageStub


@dataclass
class _ResponseStub:
    choices: list[_ChoiceStub]


class _ChatStub:
    def __init__(self, scripted_responses):
        self._scripted = list(scripted_responses)
        self.calls = []

    def create(self, **kwargs):
        self.calls.append(kwargs)
        if not self._scripted:
            raise RuntimeError("No scripted response left")
        return self._scripted.pop(0)


class _CompletionsStub:
    def __init__(self, scripted_responses):
        self.completions = _ChatStub(scripted_responses)


class _OpenAIStub:
    def __init__(self, scripted_responses):
        self.chat = _CompletionsStub(scripted_responses)


class _OracleStub:
    def execute(self, sql, max_rows=1000):
        return QueryResult(
            columns=["TOTAL_INCOME"],
            rows=[[12345.0]],
            row_count=1,
            truncated=False,
        )


def _mk_resp(tool_calls=None, content=None):
    return _ResponseStub(
        choices=[
            _ChoiceStub(
                message=_MessageStub(
                    content=content,
                    tool_calls=tool_calls,
                )
            )
        ]
    )


def _tool_call(idx, name, args):
    return _ToolCallStub(
        id=f"call_{idx}",
        function=_FuncStub(name=name, arguments=json.dumps(args)),
    )


def test_agent_loop_full_pipeline():
    scripted = [
        # 1. inspect_schema
        _mk_resp(tool_calls=[_tool_call(1, "inspect_schema", {"table": "client_product"})]),
        # 2. execute_sql
        _mk_resp(
            tool_calls=[
                _tool_call(
                    2,
                    "execute_sql",
                    {"sql": "SELECT SUM(PNL_SUM) AS TOTAL_INCOME FROM client_product"},
                )
            ]
        ),
        # 3. validate_result
        _mk_resp(
            tool_calls=[
                _tool_call(
                    3,
                    "validate_result",
                    {
                        "columns": ["TOTAL_INCOME"],
                        "row_count": 1,
                        "rows_preview": [[12345.0]],
                        "expectations": {"min_rows": 1, "non_null_columns": ["TOTAL_INCOME"]},
                    },
                )
            ]
        ),
        # 4. final_answer
        _mk_resp(
            tool_calls=[
                _tool_call(
                    4,
                    "final_answer",
                    {"text": "Общий доход составил 12 345 руб.", "supporting_data": {"total": 12345.0}},
                )
            ]
        ),
    ]
    client = _OpenAIStub(scripted)
    config = Config(
        oracle_username="u",
        oracle_password="p",
        oracle_dsn="d",
        api_key="k",
        api_url="http://x",
        sql_model="m",
        response_model="m",
    )
    result = run_agent(
        "какой общий доход?",
        config,
        client=client,  # type: ignore[arg-type]
        oracle=_OracleStub(),  # type: ignore[arg-type]
    )
    assert "12 345" in result.answer
    assert result.steps == 4
    assert result.supporting_data == {"total": 12345.0}


def test_agent_loop_handles_plain_text_response():
    """Если модель не зовёт ни одного tool — main loop возвращает её текст."""
    scripted = [_mk_resp(content="Привет, я ассистент.", tool_calls=None)]
    client = _OpenAIStub(scripted)
    config = Config(
        oracle_username="u",
        oracle_password="p",
        oracle_dsn="d",
        api_key="k",
        api_url="http://x",
        sql_model="m",
        response_model="m",
    )
    result = run_agent(
        "hi",
        config,
        client=client,  # type: ignore[arg-type]
        oracle=_OracleStub(),  # type: ignore[arg-type]
    )
    assert result.answer == "Привет, я ассистент."
    assert result.steps == 1


def test_agent_loop_recovers_empty_reply_after_execute_sql():
    """PREMORTEM #1: модель вернула пустой content после успешного
    execute_sql — recovery должен извлечь NL-ответ из tool_result'а
    через дополнительный вызов response_model."""
    scripted = [
        _mk_resp(
            tool_calls=[
                _tool_call(
                    1,
                    "execute_sql",
                    {"sql": "SELECT SUM(PNL_SUM) FROM client_product"},
                )
            ]
        ),
        # модель «забыла» вызвать final_answer и вернула пустой content
        _mk_resp(content="", tool_calls=None),
        # recovery-вызов на response_model — отдаёт связный ответ
        _mk_resp(content="Общий доход — 12 345 рублей.", tool_calls=None),
    ]
    client = _OpenAIStub(scripted)
    config = Config(
        oracle_username="u",
        oracle_password="p",
        oracle_dsn="d",
        api_key="k",
        api_url="http://x",
        sql_model="m",
        response_model="m",
    )
    result = run_agent(
        "какой общий доход?",
        config,
        client=client,  # type: ignore[arg-type]
        oracle=_OracleStub(),  # type: ignore[arg-type]
    )
    assert result.answer == "Общий доход — 12 345 рублей."

